#include <stdio.h>
#include <stdlib.h>

#define MAXN 100005
#define MAXM 200005

long long one[MAXN], two[MAXN];
long long pref1[MAXN], pref2[MAXN];
long long ans[MAXM];

int cmp(const void *a, const void *b) {
    long long x = *(long long*)a;
    long long y = *(long long*)b;
    if (x < y) return 1;
    if (x > y) return -1;
    return 0;
}

int main() {
    int N;
    scanf("%d", &N);

    int n1 = 0, n2 = 0;
    int totalWeight = 0;

    for (int i = 0; i < N; i++) {
        int w;
        long long c;
        scanf("%d %lld", &w, &c);

        totalWeight += w;

        if (w == 1)
            one[n1++] = c;
        else
            two[n2++] = c;
    }

    qsort(one, n1, sizeof(long long), cmp);
    qsort(two, n2, sizeof(long long), cmp);

    pref1[0] = 0;
    for (int i = 0; i < n1; i++)
        pref1[i + 1] = pref1[i] + one[i];

    pref2[0] = 0;
    for (int i = 0; i < n2; i++)
        pref2[i + 1] = pref2[i] + two[i];

    int k = 0;

    for (int cap = 1; cap <= totalWeight; cap++) {

        while (k + 1 <= n2 && 2 * (k + 1) <= cap) {
            int rem1 = cap - 2 * (k + 1);
            if (rem1 > n1) break;

            long long val1 = pref2[k + 1] + pref1[rem1];
            long long val2 = pref2[k] + pref1[cap - 2 * k];

            if (val1 >= val2) k++;
            else break;
        }

        int remaining = cap - 2 * k;

        if (remaining >= 0 && remaining <= n1)
            ans[cap] = pref2[k] + pref1[remaining];
        else
            ans[cap] = 0;
    }

    for (int i = 1; i <= totalWeight; i++) {
        if (ans[i] < ans[i - 1])
            ans[i] = ans[i - 1];
    }

    for (int i = 1; i <= totalWeight; i++)
        printf("%lld ", ans[i]);

    return 0;
}

