import java.io.*;
import java.util.*;

public class Main {

    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int N = fs.nextInt();

        List<Long> one = new ArrayList<>();
        List<Long> two = new ArrayList<>();
        int totalWeight = 0;

        for (int i = 0; i < N; i++) {
            int w = fs.nextInt();
            long c = fs.nextLong();
            totalWeight += w;

            if (w == 1) one.add(c);
            else two.add(c);
        }

        // Sort descending
        one.sort(Collections.reverseOrder());
        two.sort(Collections.reverseOrder());

        int n1 = one.size();
        int n2 = two.size();

        long[] pref1 = new long[n1 + 1];
        long[] pref2 = new long[n2 + 1];

        for (int i = 0; i < n1; i++)
            pref1[i + 1] = pref1[i] + one.get(i);

        for (int i = 0; i < n2; i++)
            pref2[i + 1] = pref2[i] + two.get(i);

        int M = totalWeight;
        long[] ans = new long[M + 1];

        int k = 0; // number of weight-2 items

        for (int cap = 1; cap <= M; cap++) {

            // Increase k while it improves answer
            while (k + 1 <= n2 && 2 * (k + 1) <= cap) {

                long takeMore2 = pref2[k + 1];
                int remaining1 = cap - 2 * (k + 1);
                if (remaining1 > n1) break;

                long valMore2 = takeMore2 + pref1[remaining1];

                int remainingCurrent = cap - 2 * k;
                if (remainingCurrent > n1) {
                    k++;
                    continue;
                }

                long valCurrent = pref2[k] + pref1[remainingCurrent];

                if (valMore2 >= valCurrent) k++;
                else break;
            }

            int remaining = cap - 2 * k;
            if (remaining >= 0 && remaining <= n1)
                ans[cap] = pref2[k] + pref1[remaining];
            else
                ans[cap] = 0;
        }

        // Capacity allows ≤ C
        for (int i = 1; i <= M; i++)
            ans[i] = Math.max(ans[i], ans[i - 1]);

        StringBuilder sb = new StringBuilder();
        for (int i = 1; i <= M; i++)
            sb.append(ans[i]).append(" ");

        System.out.println(sb.toString().trim());
    }

    static class FastScanner {
        BufferedReader br;
        StringTokenizer st;

        FastScanner(InputStream is) {
            br = new BufferedReader(new InputStreamReader(is));
        }

        String next() throws IOException {
            while (st == null || !st.hasMoreElements())
                st = new StringTokenizer(br.readLine());
            return st.nextToken();
        }

        int nextInt() throws IOException {
            return Integer.parseInt(next());
        }

        long nextLong() throws IOException {
            return Long.parseLong(next());
        }
    }
}
